import numpy as np

def define_qm_region(metal_center, residues, ligand, cutoff=4.0):
    """
    Define QM region for metalloprotein QM/MM.
    """
    qm_atoms = []
    boundary_atoms = []

    # 1. Always include metal
    qm_atoms.append({
        'id': 'metal',
        'symbol': metal_center['symbol'],
        'coord': metal_center['coord'],
        'type': 'metal'
    })

    # 2. Include coordinating residues (full sidechain)
    for res_name in metal_center.get('coordinating_residues', []):
        for res in residues:
            if res['name'] == res_name:
                for atom in res['atoms']:
                    if atom['name'] not in ['N', 'C', 'O']:  # Not backbone
                        qm_atoms.append({
                            'id': f"{res_name}_{atom['name']}",
                            'symbol': atom['symbol'],
                            'coord': atom['coord'],
                            'type': 'coordinating_residue'
                        })
                    if atom['name'] == 'CA':
                        # CA-CB boundary
                        boundary_atoms.append({
                            'qm_atom': f"{res_name}_CB",
                            'mm_atom': f"{res_name}_CA",
                            'type': 'link_atom'
                        })

    # 3. Include ligand (at least reactive part)
    metal_coord = np.array(metal_center['coord'])
    for atom in ligand['atoms']:
        atom_coord = np.array(atom['coord'])
        dist = np.linalg.norm(atom_coord - metal_coord)
        if dist < cutoff or atom['name'] in ligand.get('reactive_atoms', []):
            qm_atoms.append({
                'id': f"ligand_{atom['name']}",
                'symbol': atom['symbol'],
                'coord': atom['coord'],
                'type': 'ligand'
            })

    return {
        'qm_atoms': qm_atoms,
        'boundary_atoms': boundary_atoms,
        'n_qm_atoms': len(qm_atoms),
        'recommended_method': 'B3LYP-D3/6-31G*' if len(qm_atoms) < 100 else 'PM7 or GFN2-xTB'
    }
